const c3Option = (encoded) => {
  const [id, name, note] = encoded.split("|");
  return { id, name, note };
};

const c3Decision = (id, label, prompt, correct, trapOne, trapTwo, explanation) => ({
  id,
  label,
  prompt,
  options: [c3Option(correct), c3Option(trapOne), c3Option(trapTwo)],
  correct: c3Option(correct).id,
  explanation
});

const c3Phase = (id, kicker, title, instruction, conditions, slots, successTitle, successCopy) => ({
  id,
  kicker,
  title,
  instruction,
  conditions,
  condition: conditions.join(" "),
  slots,
  successTitle,
  successCopy
});

